/** Fuel log form with browser-side total preview and server-side recalculation. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/fuel_functions.php';requireAuth();enforceModuleAccess('fuel');if($_SERVER['REQUEST_METHOD']==='POST'){if(!verifyCsrfToken((string)($_POST['csrf_token']??''))){setFlash('danger','Invalid form token.');redirect('modules/fuel/add.php');}[$ok,$r]=saveFuelLog($_POST);setFlash($ok?'success':'danger',$ok?'Fuel log saved.':implode(' ',(array)$r));redirect($ok?'modules/fuel/view.php?id='.$r:'modules/fuel/add.php');}$vehicles=getDb()->query('SELECT id,registration_number FROM vehicles WHERE deleted_at IS NULL ORDER BY registration_number')->fetchAll();$trips=getDb()->query('SELECT id,trip_number FROM trips WHERE status="Dispatched" ORDER BY id DESC')->fetchAll();$stations=getDb()->query('SELECT id,name FROM fuel_stations WHERE status="Active" ORDER BY name')->fetchAll();$pageTitle='Add fuel';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content fuel-module"><?php require ROOT_PATH.'/includes/navbar.php';?><h1 class="page-title">Log fuel</h1><p class="page-subtitle">Capture a verified refueling transaction. The total is calculated server-side.</p><form class="card dashboard-card fuel-form" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><div class="form-grid"><div class="form-group"><label>Vehicle</label><select name="vehicle_id" required><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>"><?=e($v['registration_number'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Active trip</label><select name="trip_id"><option value="">No trip</option><?php foreach($trips as $t):?><option value="<?=$t['id']?>"><?=e($t['trip_number'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Fuel station</label><select name="fuel_station_id"><option value="">Not recorded</option><?php foreach($stations as $s):?><option value="<?=$s['id']?>"><?=e($s['name'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Fuel type</label><select name="fuel_type"><?php foreach(['Petrol','Diesel','CNG','Electric','Hybrid'] as $t):?><option><?=$t?></option><?php endforeach;?></select></div><div class="form-group"><label>Liters</label><input data-fuel-liters name="quantity_liters" type="number" min=".01" step=".01" required></div><div class="form-group"><label>Price per liter</label><input data-fuel-price name="price_per_liter" type="number" min="0" step=".01" required></div><div class="form-group"><label>Total cost</label><output data-fuel-total>0.00</output></div><div class="form-group"><label>Odometer</label><input name="odometer_reading" type="number" min="0" step=".01"></div><div class="form-group"><label>Fuel date</label><input name="logged_date" type="date" max="<?=date('Y-m-d')?>" required></div><div class="form-group"><label>Payment method</label><select name="payment_method"><?php foreach(['Cash','Card','UPI','Company Account'] as $p):?><option><?=$p?></option><?php endforeach;?></select></div><div class="form-group"><label>Filled by</label><input name="filled_by"></div><div class="form-group"><label>Bill number</label><input name="bill_number"></div></div><div class="form-group"><label>Remarks</label><textarea name="remarks"></textarea></div><div class="form-actions"><button class="btn btn-primary">Save fuel log</button><a class="btn btn-secondary" href="index.php">Cancel</a></div></form></main><?php require ROOT_PATH.'/includes/footer.php';?>
